'use strict';

const path = require('path');

const _ = require('lodash');
const React = require('react');
const ReactDOM = require('react-dom/server');
const { QueryClient, QueryClientProvider } = require('react-query');
const { HelmetProvider } = require('react-helmet-async');
const { matchRoutes } = require('react-router-config');
const { createMemoryHistory } = require('history');
const { stringify } = require('flatted/cjs');
const he = require('he');
const { ChunkExtractor } = require('@loadable/server');
const {
  wrapApp /* , apiClient: createApiClient */,
} = require('@openagenda/react-shared');
const {
  Html,
  LayoutManager,
  createLayoutStore,
} = require('@openagenda/react-layouts');
const {
  AgendaAdminDataLayout,
  AgendaDataLayout,
  AgendaAdminFiltersLayout,
  AgendaAdminLayout,
  AgendaLayout,
  InboxUserLayout,
  InboxAgendaAdminLayout,
  MainLayout,
  RequiredSuperAdmin,
  RequiredUser,
} = require('@openagenda/react-layouts/dist/layouts');
const createHomeApp = require('@openagenda/home/dist/app');
const createUserSettingsApp = require('@openagenda/user-apps/dist/app');
const createAgendaSettingsNewApp = require('@openagenda/agenda-settings/dist/client/createApp');
const createAgendaSettingsEditApp = require('@openagenda/agenda-settings/dist/client/editApp');
const createUserActivitiesApp = require('@openagenda/activity-apps/dist/client/apps/user');
const createAgendaActivitiesApp = require('@openagenda/activity-apps/dist/client/apps/agenda');
const createAggregatorSourcesApp = require('@openagenda/aggregator-sources/dist/app');
const createAgendaStatsApp = require('@openagenda/agenda-stats/dist/app');
const createInboxApp = require('@openagenda/inbox-apps/dist/app');
const createMembersApp = require('@openagenda/member-apps/dist/app');
const createLegacyEmbedsApp = require('@openagenda/legacy/embeds/app/dist');
const createAgendaContributeApp = require('@openagenda/agenda-contribute/dist');
const createEventAdminApp = require('@openagenda/event-admin-apps/dist/app');
const createAgendaLocationAdminApp = require('@openagenda/agenda-locations-app/dist/app');
const createAgendaSchemaAdminApp = require('@openagenda/agenda-schemas-app/dist/app');
const createSupervisorApp = require('@openagenda/supervisor/lib/app');
const RootHelmet = require('./RootHelmet');
const createReduxMiddleware = require('./reduxMiddleware');

const { createElement: el } = React;

function redirectIfNeeded(req, res, history) {
  const { pathname } = history.location;

  if (
    decodeURIComponent(req.baseUrl + req.path) !== decodeURIComponent(pathname)
  ) {
    res.redirect(302, pathname);
    return true;
  }
}

module.exports = function match({ initialState, publicPath, apiRoot }) {
  return async (req, res, next) => {
    try {
      const state = typeof initialState === 'function'
        ? await initialState(req)
        : initialState;

      const lang = state.layout?.main?.lang ?? 'fr';
      const translateMode = state.layout?.main?.translateMode ?? false;
      const outdatedBrowser = state.layout?.main?.outdatedBrowser ?? false;

      // We create an extractor from the statsFile (generated by webpack loadable plugin)
      const extractor = new ChunkExtractor({
        statsFile: path.join(__dirname, '/dist/loadable-stats.json'),
        entrypoints: outdatedBrowser ? ['outdated', 'webapp'] : ['webapp'],
        publicPath,
      });

      const history = createMemoryHistory({
        initialEntries: [req.originalUrl],
      });

      // Create store for the layout
      const layoutStore = createLayoutStore(state.layout, history);

      const reduxMiddleware = createReduxMiddleware(layoutStore);

      // const apiClient = createApiClient(apiRoot, req);

      const apps = [
        ['home', createHomeApp, MainLayout],
        ['userSettings', createUserSettingsApp, [MainLayout, RequiredUser]],
        [
          'agendaSettingsNew',
          createAgendaSettingsNewApp,
          [MainLayout, RequiredUser],
        ],
        ['userActivities', createUserActivitiesApp, [MainLayout, RequiredUser]],
        [
          'inboxUser',
          createInboxApp,
          [MainLayout, RequiredUser, InboxUserLayout],
        ],
        [
          'support',
          createInboxApp,
          [MainLayout, RequiredUser, InboxUserLayout],
        ],
        // agenda admin
        [
          'aggregatorSources',
          createAggregatorSourcesApp,
          [MainLayout, RequiredUser, AgendaAdminDataLayout, AgendaAdminLayout],
        ],
        [
          'agendaAdminInbox',
          createInboxApp,
          [
            MainLayout,
            RequiredUser,
            AgendaAdminDataLayout,
            AgendaAdminLayout,
            InboxAgendaAdminLayout,
          ],
        ],
        [
          'members',
          createMembersApp,
          [MainLayout, RequiredUser, AgendaAdminDataLayout, AgendaAdminLayout],
        ],
        [
          'agendaActivities',
          createAgendaActivitiesApp,
          [MainLayout, RequiredUser, AgendaAdminDataLayout, AgendaAdminLayout],
        ],
        [
          'agendaStats',
          createAgendaStatsApp,
          [MainLayout, RequiredUser, AgendaAdminDataLayout, AgendaAdminLayout],
        ],
        [
          'legacyEmbeds',
          createLegacyEmbedsApp,
          [
            MainLayout,
            RequiredUser,
            AgendaAdminDataLayout,
            AgendaAdminFiltersLayout,
          ],
        ],
        [
          'agendaContribute',
          createAgendaContributeApp,
          [MainLayout, RequiredUser.agenda, AgendaDataLayout, AgendaLayout],
        ],
        [
          'eventAdmin',
          createEventAdminApp,
          [
            MainLayout,
            RequiredUser,
            AgendaAdminDataLayout,
            AgendaAdminFiltersLayout,
          ],
        ],
        [
          'agendaLocationAdmin',
          createAgendaLocationAdminApp,
          [MainLayout, RequiredUser, AgendaAdminDataLayout, AgendaAdminLayout],
        ],
        [
          'agendaSchemaAdmin',
          createAgendaSchemaAdminApp,
          [MainLayout, RequiredUser, AgendaAdminDataLayout, AgendaAdminLayout],
        ],
        [
          'agendaSettingsEdit',
          createAgendaSettingsEditApp,
          [
            MainLayout,
            RequiredUser,
            AgendaAdminDataLayout,
            AgendaAdminFiltersLayout,
          ],
        ],
        // superadmin
        [
          'adminSupport',
          createInboxApp,
          [MainLayout, RequiredUser, RequiredSuperAdmin, InboxUserLayout],
        ],
        [
          'supervisor',
          createSupervisorApp,
          [MainLayout, RequiredUser, RequiredSuperAdmin],
        ],
      ].reduce(
        (accu, [key, createApp, layout]) => ({
          ...accu,
          [key]: createApp({
            req,
            history,
            initialState: state[key],
            layout,
            reduxMiddleware,
            apiRoot,
          }),
        }),
        {},
      );

      // Not found
      const notFound = Object.values(apps).every(
        app =>
          !(
            app.routes
            && matchRoutes(app.routes, history.location.pathname).some(
              v => v.route.component && !v.route.routes,
            )
          ),
      );

      if (notFound) {
        return next();
      }

      const triggerHooks = () =>
        Promise.all(
          Object.values(apps)
            .filter(app => app.triggerHooks)
            .map(app => app.triggerHooks()),
        );

      // Triggers hooks
      await triggerHooks();

      // Check if redirect in hooks
      if (redirectIfNeeded(req, res, history)) {
        return;
      }

      const staticContext = {};
      const helmetContext = {};

      const queryClient = new QueryClient({
        defaultOptions: {
          queries: {
            refetchOnWindowFocus: false,
          },
        },
      });

      const outdatedScript = outdatedBrowser
        ? el(
          'script',
          { type: 'text/javascript' },
          `window.outdatedBrowserOptions = { language: "${lang}" };`,
        )
        : null;

      const rootHelmet = el(RootHelmet, null, outdatedScript);

      const content = ReactDOM.renderToString(
        el(
          HelmetProvider,
          { context: helmetContext },
          rootHelmet,
          wrapApp(
            {
              Content: () =>
                el(
                  QueryClientProvider,
                  { client: queryClient },
                  el(LayoutManager, {
                    store: layoutStore,
                    history,
                    apps,
                  }),
                ),
              history,
              triggerHooks,
            },
            { req, staticContext, extractor },
          ),
        ),
      );

      if (staticContext.url) {
        return res.redirect(staticContext.status || 302, staticContext.url);
      }

      // Check if location change anywhere else
      if (redirectIfNeeded(req, res, history)) {
        return;
      }

      // Get initialStateForClient
      const initialStateForClient = _.mapValues(apps, app => {
        const appState = app.store.getState();

        // Avoid all settings.apiRoot
        if (_.get(appState, 'settings.apiRoot')) {
          _.set(appState, 'settings.apiRoot', '');
        }

        return appState;
      });

      // Add layout state to initialStateForClient
      initialStateForClient.layout = layoutStore.getState();
      _.set(initialStateForClient.layout, 'main.apiRoot', '');

      const serializedInitialState = he.encode(
        stringify(initialStateForClient),
      );

      // Send Html
      const html = el(Html, {
        helmet: helmetContext.helmet,
        content,
        initialState: serializedInitialState,
        extractor,
        lang,
        translateMode,
      });
      res.status(200).send(`<!doctype html>${ReactDOM.renderToString(html)}`);
    } catch (e) {
      next(e);
    }
  };
};
